Fixed alleles in other samples Using the dom_ep_fixed.vcf file as an interval file, we can now make sample-specific vcf files that only contain the 8288 sites that are fixed. In the script bdlow $sample is the sample_name found in the vcf file, $vcf is the output vcf e.g. sbatch make_vcfs.sh domestic_LIB8733 ./m_putorius/furo/LIB8733.vcf.gz sample=$1 #the sample_name found in all_samples_genotyped_snps.vcf vcf=$2 #the output VCF file source jre-8u92source gatk-4.1.3.0_spark srun gatk --java-options &#34;-Xmx5g -Xms5g -XX:ParallelGCThreads=2&#34; SelectVariants -R ../../reference/MusPutFur1.0_bionano.fasta -sn $sample -V all_samples_genotyped_snps.vcf -L dom_ep_fixed.vcf -O $vcf Next, compare the genotypes and alleles in the output vcf files to those in dom_ep_fixed.sh using a custom python script, where the input is the same as above. import vcf import sys import imp import collections vcf_master = sys.argv[1]#the vcf file to compare the other vcf file to vcf_compare = sys.argv[2]#the vcf file to compare sample_name = sys.argv[3] #the sample to allocate #open the infile master = vcf.VCFReader(filename=vcf_master) compare = vcf.VCFReader(filename=vcf_compare) #create a dictionary which will use tuples as keys, e.g. vcf_master_dict[chr01][999] = GT vcf_master_dict = {} n_master=0 n_compare=0 n_matching=0 n_matching_het=0 n_non_matching_het=0 n_hom_ref=0 n_hom_alt=0 n_not_called=0 n_not_accouted=0 n_not_in_compare=0 #loop thru each record in the master vcf for record in master: alleles=record.alleles #print(alleles) vcf_master_dict[(record.CHROM, record.POS)] = alleles n_master+=1 #loop thru each record in the compare vcf for record in compare: n_compare+=1 if (record.CHROM, record.POS) in vcf_master_dict: n_matching+=1 for sample in record.samples: #check to confirm that the sample name (sys.argv[3]) is present in our compare vcf if sample.sample == sample_name: current_genotype = sample[&#34;GT&#34;] #if it&#39;s heterozygous if current_genotype == &#39;0/1&#39; or current_genotype == &#39;0|1&#39;: if (vcf_master_dict[(record.CHROM, record.POS)] == record.alleles): n_matching_het+=1 else: n_non_matching_het+=1 #if it&#39;s homozygous ref elif current_genotype == &#39;0/0&#39; or current_genotype == &#39;0|0&#39;: alleles = vcf_master_dict[(record.CHROM, record.POS)] ref = alleles[0] if (ref == record.REF): n_hom_ref+=1 #if it&#39;s homozygous alt elif current_genotype == &#39;1/1&#39; or current_genotype == &#39;1|1&#39;: if (vcf_master_dict[(record.CHROM, record.POS)] == record.alleles): n_hom_alt+=1 #if it&#39;s not called elif current_genotype == &#39;./.&#39; or current_genotype == &#39;.|.&#39;: n_not_called+=1 else: n_not_accouted+=1 sys.stderr.write(&#34;
