The following record was not found in the master vcf: &#34;) sys.stderr.write(str(record)) #n_combined = n_matching_het + n_hom_ref + n_hom_alt part_het = float(n_matching_het)/float(n_compare) part_non_matching_het = float(n_non_matching_het)/float(n_compare) part_hom_ref = float(n_hom_ref)/float(n_compare) part_hom_alt = float(n_hom_alt)/float(n_compare) part_not_called=float(n_not_called)/float(n_compare) part_not_accouted=float(n_not_accouted)/float(n_compare) part_not_in_compare=float(n_not_in_compare)/float(n_compare) #How many records were missing from the compare vcf (which were present in the master vcf) n_master_minus_n_compare=n_master - n_compare part_not_found=float(n_master_minus_n_compare)/float(n_master) count_num_compare=n_matching_het+n_non_matching_het+n_hom_ref+n_hom_alt+n_not_called+n_not_accouted check_num_compare=float(count_num_compare)/float(n_compare) check_parts_compare=part_non_matching_het+part_het+part_hom_ref+part_hom_alt+part_not_called+part_not_accouted+part_not_in_compare sys.stderr.write(&#34;Number of sites in master &#34;+ str(n_master)+ &#34;
